"""Нормализация тегов по формату из конфига (отправка в LLM и разбор ответа)."""from __future__ import annotationsimport redef normalize_tag_structure(tag: str) -> str:    """Пробелы и дефисы → _, убрать лишнее; без правил регистра."""    s = (tag or "").strip()    if not s:        return ""    s = re.sub(r"\s+", "_", s)    s = s.replace("-", "_")    s = re.sub(r"[^\w_]", "", s, flags=re.UNICODE)    s = re.sub(r"_+", "_", s).strip("_")    return sdef _segment_letters_all_uppercase(segment: str) -> bool:    """True, если в сегменте есть буквы и каждая буква в верхнем регистре (аббревиатура)."""    letters = [c for c in segment if c.isalpha()]    if not letters:        return False    return all(c.isupper() for c in letters)def _format_tag_name_segment(segment: str) -> str:    """Tag_name: сегмент целиком в ВЕРХНЕМ — без изменений; иначе только первая буква — заглавная, остальное как есть."""    if not segment:        return ""    if _segment_letters_all_uppercase(segment):        return segment    return segment[0].upper() + segment[1:]def apply_tag_format(structured: str, fmt: str) -> str:    """Регистр: tag_name — всё строчными; Tag_name — по сегментам: ALLCAPS не трогаем, иначе capitalized только первый символ."""    if not structured:        return ""    if fmt == "tag_name":        return structured.lower()    parts = [p for p in structured.split("_") if p]    if not parts:        return ""    return "_".join(_format_tag_name_segment(p) for p in parts)def normalize_tag(tag: str, fmt: str) -> str:    """Структура + формат регистра."""    s = normalize_tag_structure(tag)    if not s:        return ""    return apply_tag_format(s, fmt)def parse_start_tag_set(raw: str, tag_format: str) -> list[str]:    """Стартовый набор из текста конфига: запятые и переносы; канонический вид по tag_format."""    if not raw or not isinstance(raw, str):        return []    parts = re.split(r"[\n,]+", raw)    out: list[str] = []    seen: set[str] = set()    for p in parts:        tag = (p or "").strip()        if not tag:            continue        norm = normalize_tag(tag, tag_format)        if not norm:            continue        if norm not in seen:            seen.add(norm)            out.append(norm)    return out